import { useUserStore } from '@/store/modules/user'

export const hasPermi = {
  mounted(el: HTMLElement, binding: any) {
    const { value } = binding
    const userStore = useUserStore()
    const all_permission = '*:*:*'
    const permissions = userStore.permissions || []

    if (value && value instanceof Array && value.length > 0) {
      const perms = value
      const hasPermissions = permissions.some((v) => {
        return all_permission === v || perms.includes(v)
      })
      if (!hasPermissions) {
        el.parentNode && el.parentNode.removeChild(el)
      }
    } else {
      throw new Error(`请设置操作权限标签值`)
    }
  }
}

import { useUserStore } from '@/store/modules/user'

export const hasRole = {
  mounted(el: HTMLElement, binding: any) {
    const { value } = binding
    const userStore = useUserStore()
    const super_admin = 'admin'
    const roles = userStore.roles || []

    if (value && value instanceof Array && value.length > 0) {
      const roleFlag = value
      const hasRole = roles.some((v) => {
        return super_admin === v || roleFlag.includes(v)
      })
      if (!hasRole) {
        el.parentNode && el.parentNode.removeChild(el)
      }
    } else {
      throw new Error(`请设置角色权限标签值`)
    }
  }
}

import { defineStore } from 'pinia'

export const useDictStore = defineStore('dict', {
  state: () => ({
    dict: new Array<any>()
  }),
  actions: {
    // 获取字典
    getDict(_key: string): any {
      if (_key == null && _key == '') {
        return null
      }
      try {
        for (let i = 0; i < this.dict.length; i++) {
          if (this.dict[i].key == _key) {
            return this.dict[i].value
          }
        }
      } catch (e) {
        return null
      }
      return null
    },
    // 设置字典
    setDict(_key: string, value: any) {
      if (_key !== null && _key !== '') {
        this.dict.push({
          key: _key,
          value: value
        })
      }
    },
    // 删除字典
    removeDict(_key: string) {
      let bln = false
      try {
        for (let i = 0; i < this.dict.length; i++) {
          if (this.dict[i].key == _key) {
            this.dict.splice(i, 1)
            return true
          }
        }
      } catch (e) {
        bln = false
      }
      return bln
    },
    // 清空字典
    cleanDict() {
      this.dict = new Array<any>()
    },
    // 初始字典
    initDict() {}
  }
})

export default useDictStore
